import nmap
import scapy.all as scapy
import requests

class VulnerabilityScanner:
    def __init__(self, ip_address):
        self.ip_address = ip_address
        self.nmap = nmap.PortScanner()

    def scan_ports(self):
        self.nmap.scan(self.ip_address, '1-65535', '-sS -O')
        return self.nmap.all_hosts()

    def identify_device_types(self, hosts):
        device_types = {}
        for host in hosts:
            device_type = self.nmap[host]['osmatch'][0]['name']
            device_types[host] = device_type
        return device_types

    def detect_vulnerabilities(self, hosts):
        vulnerabilities = {}
        for host in hosts:
            url = f'http://{host}/'
            try:
                response = requests.get(url)
                if response.status_code == 200:
                    vulnerabilities[host] = 'Device is online and responding to HTTP requests'
                else:
                    vulnerabilities[host] = 'Device is offline or not responding to HTTP requests'
            except requests.exceptions.RequestException:
                vulnerabilities[host] = 'Device is offline or not responding to HTTP requests'
        return vulnerabilities

    def scan(self):
        hosts = self.scan_ports()
        device_types = self.identify_device_types(hosts)
        vulnerabilities = self.detect_vulnerabilities(hosts)
        return device_types, vulnerabilities

def main():
    ip_address = input('Enter the IP address of the smart home device: ')
    scanner = VulnerabilityScanner(ip_address)
    device_types, vulnerabilities = scanner.scan()
    print('Device Types:')
    for host, device_type in device_types.items():
        print(f'{host}: {device_type}')
    print('\nVulnerabilities:')
    for host, vulnerability in vulnerabilities.items():
        print(f'{host}: {vulnerability}')

if __name__ == '__main__':
    main()

